    if (!leaf) {
      const leftLeaf = workspace.getLeftLeaf(false);
      if (!leftLeaf)
        return;
      leaf = leftLeaf;
      await leaf.setViewState({
        type: NarrativeSidebarView.VIEW_TYPE,
        active: true
      });
    }
    workspace.revealLeaf(leaf);
